// Liquid Mirror — noise feeds back through itself, osc overlay adds structure
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.78; AUDIO.gain = 50; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.4, 0.03);
var mid  = env(_mi, 0.35, 0.04);
var high = env(_hi, 0.3, 0.05);
var amp  = function(){ return (low() + mid() + high()) * 0.7 };

// noise warped by osc, inverted for negative-space effect
noise(3, 0.08)
  .modulateScale(osc(8, 0.05, 0), 0.12)
  .invert(0.6)
  .color(
    () => 0.6 + low() * 1.0,
    () => 0.5 + mid() * 0.8,
    () => 0.3 + high() * 1.0
  )
  .add(osc(15, 0.04, 2.0).color(0.2, 0.15, 0.3).rotate(() => time * 0.03), 0.3)
  .modulate(src(o0), () => 0.01 + low() * 0.004)
  .blend(src(o0).hue(() => 0.003 + amp() * 0.005).colorama(() => 0.002 + mid() * 0.004), 0.83)
  .saturate(() => 1.2 + low() * 0.5)
  .contrast(() => 1.03 + low() * 0.1)
  .brightness(() => 0.03 + low() * 0.03)
  .out(o0)
